DROP TABLE IF EXISTS flights_rset;
CREATE TABLE flights_rset (
    flight_num  INT,
    airline     TEXT,
    origin      TEXT,
    dest        TEXT,
    sched_dep   int4range[],  -- scheduled departure (exact singleton interval; grouping key)
    act_dep     int4range[],  -- actual departure (multi-day merged range set)
    sched_arr   int4range[],  -- scheduled arrival (exact singleton interval)
    act_arr     int4range[],  -- actual arrival (multi-day merged range set)
    u_r         INT
);
 
